solutions.cpp:
#include <iostream>
using namespace std;
class Solution {
public:
    int deque(vector<int>& nums, int n) {
        if (n <= 0 || n >= nums.size()) {
            return -1;
        }
        int index = (n - 1) % (nums.size() - 1);
        return nums[index];
    }
};
int main() {
    Solution s;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    cout << s.deque(nums, n);
    return 0;
}
